	ready, err = s.ReadyExecution()
	require.NoError(t, err)
	found := false
	for _, b := range ready {
		if b.ID == blocked.ID {
			found = true
		}
	}
	if !found {
		t.Errorf("unblocked bead %s should appear in ReadyExecution after recheck but was absent", blocked.ID)
	}
