	require.NoError(t, s.Close(testCtx(), parent.ID))

	ready, err = s.ReadyExecution()
	require.NoError(t, err)
	found := false
	for _, b := range ready {
		if b.ID == child.ID {
			found = true
		}
	}
	if !found {
		t.Errorf("child bead %s should be ready after parent closed but was absent", child.ID)
	}
}

